onClick:
{{
  (function() {
    if (!inp_customer_name.text) {
      showAlert('Company name is required', 'warning');
      return;
    }
    qry_customer_create.run(
      async function() {
        // Capture and store the new customer ID before anything else
        await storeValue('new_customer_id', qry_customer_create.data[0].customer_id);

        if (inp_site_contact.text || inp_site_phone.text || inp_site_email.text) {
          qry_site_create.run(
            function() {
              showAlert(
                inp_customer_name.text + ' created successfully',
                'success'
              );
              navigateTo('Home', {}, 'SAME_WINDOW');
            },
            function() {
              showAlert('Customer saved but site contact failed', 'warning');
              navigateTo('Home', {}, 'SAME_WINDOW');
            }
          );
        } else {
          showAlert(
            inp_customer_name.text + ' created successfully',
            'success'
          );
          navigateTo('Home', {}, 'SAME_WINDOW');
        }
      },
      function() {
        showAlert('Failed to create customer — check all fields', 'error');
      }
    );
  })()
}}
